def dl(fig,h=380):
    fig.update_layout(template=PTMPL,height=h,plot_bgcolor=PLOT_BG,paper_bgcolor=PAPER_BG,
        font=dict(color=FONT_COLOR,size=12),margin=dict(t=40,b=20,l=10,r=10),
        legend=dict(bgcolor="#161b22",bordercolor="#30363d",borderwidth=1,font=dict(color="#ffffff")),
        xaxis=dict(gridcolor=GRID_COLOR,linecolor="#30363d",tickfont=dict(color="#ffffff"),title_font=dict(color="#ffffff")),
        yaxis=dict(gridcolor=GRID_COLOR,linecolor="#30363d",tickfont=dict(color="#ffffff"),title_font=dict(color="#ffffff")))
    return fig

def leg(txt):
    st.markdown('<div class="legend-box">📖 ' + txt + '</div>', unsafe_allow_html=True)

def fac_c(df,col="Facultad"):
    df[col+"_c"]=df[col].map(FAC_SHORT).fillna(df[col]); return df

def to_xlsx(df):
    buf=io.BytesIO()
    with pd.ExcelWriter(buf,engine="openpyxl") as w:
        df.to_excel(w,index=False,sheet_name="Datos")
    return buf.getvalue()


