@st.cache_data
def load_period(p):
    def d(k): return pd.read_csv(io.StringIO(base64.b64decode(b[k]).decode()))
    return {k: d(f"{p}_{k}") for k in ["res","det","fac","doc","pd_fac","pd_det",
        "conf_doc","conf_sala","ef_fac","ef_ed","ef_det","opt","conc_mod","conc_fac_mod","conc_turno","prox"]}

@st.cache_data
def load_rev():
    return pd.read_csv(io.StringIO(base64.b64decode(b["rev"]).decode()))

