# Load data for selected period(s)
data = {p: load_period(p) for p in periodos}

def get_merged(key, col_periodo=True):
    dfs=[]
    for p in periodos:
        df=data[p][key].copy()
        if col_periodo: df["Periodo"]="2026-01" if p=="202601" else "2026-02"
        dfs.append(df)
    return pd.concat(dfs,ignore_index=True) if len(dfs)>1 else dfs[0]

df_res = get_merged("res")
df_det = get_merged("det")
df_fac_raw = get_merged("fac")
df_doc_raw = get_merged("doc",col_periodo=False)

df_res["Ed_corto"]=df_res["Edificio"].map(ED_SHORT).fillna(df_res["Edificio"])
df_det["Ed_corto"]=df_det["Edificio"].map(ED_SHORT).fillna(df_det["Edificio"])
df_res["Dia"]=pd.Categorical(df_res["Dia"],categories=DIAS_ORDER,ordered=True)
df_det["Dia"]=pd.Categorical(df_det["Dia"],categories=DIAS_ORDER,ordered=True)
df_fac_raw["Fac_corto"]=df_fac_raw["Facultad"].map(FAC_SHORT).fillna(df_fac_raw["Facultad"])

ocup_ed=df_res.drop_duplicates(["Edificio","Periodo"] if "Periodo" in df_res.columns else ["Edificio"])[["Ed_corto","Pct_Global_Edificio","Bloques_Posibles_Ed","Bloques_Ocupados_Ed"]].groupby("Ed_corto").agg({"Pct_Global_Edificio":"mean","Bloques_Posibles_Ed":"sum","Bloques_Ocupados_Ed":"sum"}).reset_index()
global_ocp=ocup_ed["Bloques_Ocupados_Ed"].sum()
global_pos=ocup_ed["Bloques_Posibles_Ed"].sum()
PCT_GLOBAL=round(global_ocp/global_pos*100,1)

