        fig2.update_traces(textfont=dict(color="#ffffff",size=11)); fig2.update_xaxes(tickangle=-20); dl(fig2,260)
        st.plotly_chart(fig2,use_container_width=True)
        leg("<b>Heatmap:</b> cada celda = % ocupación de un edificio en un módulo. Verde oscuro = mucha disponibilidad. Rojo = saturación. Permite identificar de un vistazo qué edificio y módulo están más comprometidos.")
        p3=fr.groupby("Modulo")[["Libres","Ocupadas"]].mean().reset_index(); p3["ML"]=p3["Modulo"].map(MODULOS)
