        e2.metric("Salas sobredimensionadas (<30%)",f"{muy_baja} ({round(muy_baja/total_reg*100,1)}%)")
        e3.metric("Uso óptimo o exceso (>90%)",f"{exceso_ef} ({round(exceso_ef/total_reg*100,1)}%)")
        leg("<b>Ratio = Cupo sección / Capacidad sala × 100.</b> <b>Muy baja (<30%):</b> sala sobredimensionada — mover a sala más pequeña libera una sala grande para otras secciones. <b>Baja (30-50%):</b> sala moderadamente grande. <b>Alta (70-90%):</b> uso eficiente. <b>Óptima/Exceso (>90%):</b> al límite o el cupo supera la capacidad — error urgente a corregir.")

        # Filtro por facultad
        facs_ef=sorted(ef_fac["Fac_corto"].unique())
        sel_fac_ef=st.multiselect("🎓 Filtrar por facultad",facs_ef,key="fac_ef")
        if sel_fac_ef:
            ef_fac_f=ef_fac[ef_fac["Fac_corto"].isin(sel_fac_ef)]
        else:
            ef_fac_f=ef_fac

        c1,c2=st.columns(2)
        with c1:
            cat_tot=ef_fac_f.groupby("Categoria_eficiencia")["Registros"].sum().reset_index()
            fig_e1=px.pie(cat_tot,values="Registros",names="Categoria_eficiencia",
                color_discrete_sequence=[RED,ORANGE,"#f1c40f",GREEN,CYAN])
            dl(fig_e1,300); st.plotly_chart(fig_e1,use_container_width=True)
        with c2:
            ef_r=ef_fac_f.groupby("Fac_corto").apply(lambda x:(x["Registros"]*x["Ratio_prom"]).sum()/x["Registros"].sum()).reset_index()
            ef_r.columns=["Facultad","Ratio_prom"]; ef_r=ef_r.sort_values("Ratio_prom",ascending=True)
            fig_e2=px.bar(ef_r,x="Ratio_prom",y="Facultad",orientation="h",
                color="Ratio_prom",color_continuous_scale=[[0,"#1e3a5f"],[0.7,GREEN],[1,RED]],
                range_color=[0,120],text="Ratio_prom",labels={"Ratio_prom":"Ratio (%)","Facultad":""})
            fig_e2.update_traces(texttemplate="%{text:.1f}%",textposition="outside",textfont=dict(color="#ffffff",size=12))
            fig_e2.add_vline(x=100,line_dash="dash",line_color=RED,line_width=1.5)
            dl(fig_e2,300); fig_e2.update_layout(coloraxis_showscale=False,xaxis_range=[0,135])
            st.plotly_chart(fig_e2,use_container_width=True)

        ef_ed["Categoria_eficiencia"]=pd.Categorical(ef_ed["Categoria_eficiencia"],categories=EFCAT_ORDER,ordered=True)
        fig_e3=px.bar(ef_ed.sort_values("Categoria_eficiencia"),x="Registros",y="EDIFICIO",color="Categoria_eficiencia",
            orientation="h",barmode="stack",color_discrete_sequence=[RED,ORANGE,"#f1c40f",GREEN,CYAN],
            category_orders={"Categoria_eficiencia":EFCAT_ORDER},labels={"Registros":"N° clases","EDIFICIO":""})
        dl(fig_e3,280); st.plotly_chart(fig_e3,use_container_width=True)
        leg("<b>Eficiencia por edificio:</b> distribución de clases por categoría de uso. Un edificio con mucho rojo/naranja tiene muchas secciones en salas demasiado grandes.")

        st.markdown("#### Casos críticos")
        ef_d=ef_det.copy()
        ef_d["Edificio"]=ef_d["EDIFICIO"].map(ED_SHORT).fillna(ef_d["EDIFICIO"])
        ef_d["Facultad"]=ef_d["FACULTAD"].map(FAC_SHORT).fillna(ef_d["FACULTAD"])
        cat_f=st.multiselect("Filtrar categoría",EFCAT_ORDER,default=["Muy baja (<30%)","Óptima/Exceso (>90%)"])
        fac_ef2=st.multiselect("Filtrar facultad",sorted(ef_d["Facultad"].unique()),key="fac_ef2")
        ef_show=ef_d[["ID_ASIG","ASIGNATURA","SECCION","TIPO","Facultad","LUGAR","Edificio","CUPO","CAPACIDAD","Ratio_uso","Categoria_eficiencia"]].copy()
        ef_show.columns=["ID Asig.","Asignatura","Secc.","Tipo","Facultad","Sala","Edificio","Cupo","Cap.","Ratio %","Categoría"]
        if cat_f: ef_show=ef_show[ef_show["Categoría"].isin(cat_f)]
        if fac_ef2: ef_show=ef_show[ef_show["Facultad"].isin(fac_ef2)]
        st.dataframe(ef_show,use_container_width=True,hide_index=True)
        st.download_button("⬇️ Descargar Excel",to_xlsx(ef_show),"eficiencia_critica.xlsx","application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")

        # OPTIMIZACIÓN
        st.markdown("---")
        st.markdown("#### 🔄 Sugerencias de optimización de salas")
        leg("<b>Optimización:</b> secciones que actualmente ocupan una sala más grande de lo necesario, y para las que existe una sala más pequeña disponible en el mismo edificio, día y módulo que también las acomodaría. Al mover la sección a una sala más ajustada, la sala grande queda libre para secciones que la necesiten. <b>Ratio actual:</b> uso actual (cupo/capacidad). <b>Ratio nuevo:</b> uso si se mueve a la sala sugerida. <b>Mejora:</b> puntos porcentuales ganados.")
        if not df_opt.empty and "Asignatura" in df_opt.columns:
            fac_opt=st.multiselect("Filtrar por facultad",sorted(df_opt["Facultad"].unique()) if "Facultad" in df_opt.columns else [],key="fac_opt")
            df_opt_show=df_opt.copy()
            df_opt_show["Facultad_c"]=df_opt_show["Facultad"].map(FAC_SHORT).fillna(df_opt_show["Facultad"]) if "Facultad" in df_opt_show.columns else ""
            if fac_opt: df_opt_show=df_opt_show[df_opt_show["Facultad_c"].isin(fac_opt)]
            cols_opt=["ID_Asig","Asignatura","Seccion","Tipo","Facultad_c","Edificio","Dia","Modulo","Sala_actual","Cap_actual","Cupo","Ratio_actual","Sala_sugerida","Cap_sugerida","Ratio_nuevo","Mejora_ratio"]
            cols_opt_exist=[c for c in cols_opt if c in df_opt_show.columns]
            df_opt_disp=df_opt_show[cols_opt_exist].copy()
            rename_map={"ID_Asig":"ID Asig.","Asignatura":"Asignatura","Seccion":"Secc.","Tipo":"Tipo","Facultad_c":"Facultad","Edificio":"Edificio","Dia":"Día","Modulo":"Mód.","Sala_actual":"Sala actual","Cap_actual":"Cap. actual","Cupo":"Cupo","Ratio_actual":"Ratio actual %","Sala_sugerida":"Sala sugerida","Cap_sugerida":"Cap. sugerida","Ratio_nuevo":"Ratio nuevo %","Mejora_ratio":"Mejora (pp)"}
            df_opt_disp=df_opt_disp.rename(columns={k:v for k,v in rename_map.items() if k in df_opt_disp.columns})
            st.info(f"{len(df_opt_disp)} sugerencias de optimización")
            st.dataframe(df_opt_disp,use_container_width=True,hide_index=True)
            st.download_button("⬇️ Descargar Excel",to_xlsx(df_opt_disp),"optimizacion_salas.xlsx","application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
        else:
            st.info("No hay sugerencias de optimización disponibles para este período.")

